const items = $input.all();
const results = [];
const batchId = $node["Upload Webhook"].json.body.batchId || ('xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) { const r = Math.random() * 16 | 0; const v = c === 'x' ? r : (r & 0x3 | 0x8); return v.toString(16); }));
const defaultCountryCode = process.env.DEFAULT_COUNTRY_CODE || '+34';

function toDateString(value) {
  if (typeof value === 'number') {
    const d = new Date((value - 25569) * 24 * 60 * 60 * 1000);
    return d.toISOString().split('T')[0];
  }
  if (value instanceof Date) {
    return value.toISOString().split('T')[0];
  }
  return value ? String(value).trim() : '';
}

function toTimeString(value) {
  if (typeof value === 'number') {
    const d = new Date(value * 24 * 60 * 60 * 1000);
    return d.toISOString().split('T')[1].slice(0, 5);
  }
  if (value instanceof Date) {
    return value.toISOString().split('T')[1].slice(0, 5);
  }
  return value ? String(value).trim() : '';
}

for (let i = 0; i < items.length; i++) {
  const row = items[i].json;
  const errors = [];
  let phone = row.patient_phone ? String(row.patient_phone).trim() : '';
  const appointmentDate = toDateString(row.appointment_date);
  const appointmentTime = toTimeString(row.appointment_time);

  // Basic Validation and Normalization
  if (!row.patient_name || String(row.patient_name).trim() === '') {
    errors.push('patient_name: Patient name is required');
  }

  if (phone === '') {
    errors.push('patient_phone: Phone number is required');
  } else {
    // Phone normalization (if country code missing)
    if (!phone.startsWith('+')) {
      if (phone.startsWith('00')) {
        phone = '+' + phone.substring(2);
      } else if (defaultCountryCode) {
        // Strip leading zeros if present when appending default country code
        const cleanPhone = phone.replace(/^0+/, '');
        phone = defaultCountryCode + cleanPhone;
      }
    }

    // Validate against E.164 regex
    if (!/^\+[1-9]\d{6,14}$/.test(phone)) {
      errors.push(`patient_phone: Invalid format ${phone}. Expected international format (e.g., +34612345678)`);
    }
  }

  if (!appointmentDate || !/^\d{4}-\d{2}-\d{2}$/.test(appointmentDate)) {
    errors.push('appointment_date: Invalid format. Expected YYYY-MM-DD');
  }

  if (!appointmentTime || !/^([01]\d|2[0-3]):([0-5]\d)$/.test(appointmentTime)) {
    errors.push('appointment_time: Invalid format. Expected HH:MM');
  }

  if (!row.appointment_type || String(row.appointment_type).trim() === '') {
    errors.push('appointment_type: Appointment type is required');
  }

  results.push({
    json: {
      rowNumber: i + 1,
      patient_name: row.patient_name ? String(row.patient_name).trim() : '',
      patient_phone: phone,
      appointment_date: appointmentDate,
      appointment_time: appointmentTime,
      appointment_type: row.appointment_type ? String(row.appointment_type).trim() : '',
      batch_id: batchId,
      is_valid: errors.length === 0,
      errors: errors.length > 0 ? errors : null
    }
  });
}

return results;

const items = $input.all();
const batchId = items[0]?.json?.batch_id || 'unknown';
const validRecords = items.filter(i => i.json.is_valid);
const invalidRecords = items.filter(i => !i.json.is_valid);

return [{
  json: {
    batchId: batchId,
    totalRecords: items.length,
    validRecords: validRecords.length,
    invalidRecords: invalidRecords.length,
    status: "processing",
    message: `File received and validated. Sending ${validRecords.length} notifications.`,
    invalidDetails: invalidRecords.map(i => ({
      rowNumber: i.json.rowNumber,
      patientName: i.json.patient_name,
      errors: i.json.errors
    }))
  }
}];

const summary = $node["Get Batch Stat Summary"].json;
const failedDetails = $input.all();
const batchId = $node["Get Results Webhook"].json.params.batchId;

return [{
  json: {
    batchId: batchId,
    status: (summary.pending > 0) ? "processing" : "completed",
    summary: {
      totalAppointments: Number(summary.total || 0),
      sent: Number(summary.sent || 0),
      failed: Number(summary.failed || 0),
      pending: Number(summary.pending || 0)
    },
    failedRecords: failedDetails.map(item => ({
      patientName: item.json.patient_name,
      phoneNumber: item.json.patient_phone,
      errorReason: item.json.error_reason,
      retryCount: item.json.retry_count
    }))
  }
}];
